// ============================================================
//  EXPAND CONTENT TEMPLATES — v5
//  Universal template matching for all content types
//  Supports: carousel pages, reel scenes, story variants, etc.
// ============================================================

const allItems = $('Prepare Visual Requests').all().map(i => i.json);
const allTemplates = $input.all().map(i => i.json).filter(t => t.uuid);

console.log('Total Placid templates loaded: ' + allTemplates.length);

// ── CONFIGURATION: Define matching patterns per content type ──
const contentTypeConfig = {
  carousel: {
    pattern: /\(page-(\d+)\)/i,
    multiTemplate: true,
    sortKey: 'pageNum'
  },
  reel: {
    pattern: /\(scene-(\d+)\)/i,
    multiTemplate: true,
    sortKey: 'sceneNum',
    fallbackToSingle: true
  },
  single_image: {
    pattern: /\(variant-([a-z0-9]+)\)/i,
    multiTemplate: false,
    sortKey: null
  },
  story: {
    pattern: /\(version-(\d+)\)/i,
    multiTemplate: false,
    sortKey: null,
    fallbackToSingle: true
  }
};

// ── HELPER: Normalize string for fuzzy matching ──
const normalizeStr = s => s.toLowerCase().replace(/\s+/g, '').trim();

// ── HELPER: Find templates matching a name pattern ──
function findMatchingTemplates(templateName, contentType, allTemplates) {
  const config = contentTypeConfig[contentType];

  if (!config) {
    return { templates: [], totalItems: 0 };
  }

  const normalizedInput = normalizeStr(templateName);
  console.log(`[${contentType}] Looking for: "${templateName}"`);

  const matchedTemplates = allTemplates
    .filter(t => {
      const title = (t.title || t.name || '').trim();
      const normalizedTitle = normalizeStr(title);

      const hasPattern = config.pattern.test(title);

      if (config.multiTemplate && !hasPattern) return false;

      const baseName = title.replace(config.pattern, '').trim();
      const normalizedBase = normalizeStr(baseName);

      const matched = normalizedBase === normalizedInput;
      if (matched) console.log(`  ✅ Matched: "${title}"`);
      return matched;
    })
    .map(t => {
      const title = (t.title || t.name || '').trim();
      const match = title.match(config.pattern);

      const sequenceValue = match ? (
        isNaN(match[1]) ? match[1] : parseInt(match[1])
      ) : 0;

      return {
        sequenceNum: sequenceValue,
        uuid: t.uuid,
        name: title,
        layers: t.layers || [],
        [config.sortKey || 'index']: sequenceValue
      };
    })
    .filter(t => t.uuid);

  if (config.multiTemplate && config.sortKey) {
    matchedTemplates.sort((a, b) => a.sequenceNum - b.sequenceNum);
  }

  console.log(`  Found ${matchedTemplates.length} template(s)`);

  // ── FALLBACK: Try exact name match if no pattern matches found ──
  if (matchedTemplates.length === 0 && config.fallbackToSingle) {
    console.log(`  ⚠️ No pattern matches, trying exact name match...`);

    const exactMatch = allTemplates.find(t => {
      const title = (t.title || t.name || '').trim();
      return normalizeStr(title) === normalizedInput;
    });

    if (exactMatch) {
      console.log(`  ✅ Found exact match: "${exactMatch.title || exactMatch.name}"`);
      return {
        templates: [{
          sequenceNum: 1,
          uuid: exactMatch.uuid,
          name: exactMatch.title || exactMatch.name,
          layers: exactMatch.layers || []
        }],
        totalItems: 1
      };
    }
  }

  return {
    templates: matchedTemplates,
    totalItems: config.multiTemplate ? matchedTemplates.length : (matchedTemplates.length > 0 ? 1 : 0)
  };
}

// ── MAIN PROCESSING ──
const results = [];

for (const item of allItems) {
  const { contentType, templateName } = item;

  if (templateName && templateName.trim() !== '') {
    const { templates, totalItems } = findMatchingTemplates(
      templateName.trim(),
      contentType,
      allTemplates
    );

    if (templates.length === 0) {
      console.log(`⚠️ No templates found for ${contentType}: "${templateName}"`);
    }

    if (contentType === 'carousel') {
      // ── One output object per slide, with only that slide's template ──
      for (const template of templates) {
        results.push({
          json: {
            ...item,
            slideNum: template.sequenceNum,
            totalSlides: totalItems,
            templateId: template.uuid,
            currentTemplate: template,
          }
        });
      }

    } else if (contentType === 'reel') {
      results.push({
        json: {
          ...item,
          templates,
          totalScenes: totalItems,
          templateId: templates.length > 0 ? templates[0].uuid : item.templateId
        }
      });

    } else {
      // single_image, story, etc.
      results.push({
        json: {
          ...item,
          matchedTemplate: templates.length > 0 ? templates[0] : null,
          templateId: templates.length > 0 ? templates[0].uuid : item.templateId
        }
      });
    }

  } else {
    // No template name - pass through unchanged
    results.push({ json: item });
  }
}

console.log(`\n✅ Processed ${results.length} items`);
return results;

// ============================================================
//  CREATIVE REQUEST BUILDER — v2
//  + Media URLs: parsed, classified, and attached to each request
// ============================================================

const items = $input.all();
const data = $('Read Calendar').all().map(i => {
  const j = i.json;
  j._type = (j.ContentType || '')
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '_');
  return j;
});

function extractTemplateId(preferredTemplate) {
  if (!preferredTemplate) return null;
  const matchWithId = preferredTemplate.match(/\(Id:([^)]+)\)/i);  // Add 'i' flag here
  if (matchWithId) return matchWithId[1].trim();
  const matchDirect = preferredTemplate.match(/\(([a-f0-9\-]{36})\)/i);
  if (matchDirect) return matchDirect[1].trim();
  return null;
}
function extractTemplateName(preferredTemplate) {
  if (!preferredTemplate || !preferredTemplate.toString().trim()) return '';
  return preferredTemplate
    .toString()
    .replace(/\(Id:[^)]+\)/i, '')
    .replace(/\([a-f0-9\-]{36}\)/i, '')
    .replace(/\([a-z0-9]+\)/i, '')
    .trim();
}

function extractDuration(preferredTemplate) {
  if (!preferredTemplate) return null;
  const match = preferredTemplate.match(/\(Duration:([^)]+)\)/i);
  return match ? match[1].trim() : null;
}

function parseMediaUrls(raw) {
  if (!raw || !raw.toString().trim()) {
    return { useDefaultMedia: true };
  }
  const urls = raw
    .toString()
    .split(/[,;\n|]+/)
    .map(u => u.trim())
    .filter(u => u.length > 0 && u.startsWith('http'));
  if (urls.length === 0) {
    return { useDefaultMedia: true };
  }
  const result = { useDefaultMedia: false };
  urls.forEach((url, i) => {
    result[`media_url_${i + 1}`] = url;
  });
  result.totalMediaUrls = urls.length;
  return result;
}

const images    = data.filter(d => d._type === 'single_image');
const carousels = data.filter(d => d._type === 'carousel');
const reels     = data.filter(d => d._type === 'reel');
const stories   = data.filter(d => d._type === 'story');

const tpl = {
  single_image: {
    Education:   'YOUR_SINGLE_IMG_EDU_TEMPLATE_ID',
    Inspiration: 'YOUR_SINGLE_IMG_INS_TEMPLATE_ID',
    Promotion:   'YOUR_SINGLE_IMG_PRO_TEMPLATE_ID'
  },
  carousel: {
    Education:   'YOUR_CAROUSEL_EDU_TEMPLATE_ID',
    Inspiration: 'YOUR_CAROUSEL_INS_TEMPLATE_ID',
    Promotion:   'YOUR_CAROUSEL_PRO_TEMPLATE_ID'
  },
  reel: {
    Education:   'YOUR_REEL_EDU_TEMPLATE_ID',
    Inspiration: 'YOUR_REEL_INS_TEMPLATE_ID',
    Promotion:   'YOUR_REEL_PRO_TEMPLATE_ID'
  },
  story: {
    Poll:         'YOUR_STORY_POLL_TEMPLATE_ID',
    Question:     'YOUR_STORY_QST_TEMPLATE_ID',
    Quote:        'YOUR_STORY_QTE_TEMPLATE_ID',
    BTS:          'YOUR_STORY_BTS_TEMPLATE_ID',
    Image:        'YOUR_STORY_IMG_TEMPLATE_ID',
    Tip:          'YOUR_STORY_TIP_TEMPLATE_ID',
    Video:        'YOUR_STORY_VID_TEMPLATE_ID',
    Quiz:         'YOUR_STORY_QIZ_TEMPLATE_ID',
    Motivational: 'YOUR_STORY_MOT_TEMPLATE_ID'
  }
};

const weekDate = images.length
  ? images[0].ScheduledDate
  : (stories.length ? stories[0].ScheduledDate : 'unknown');

const requests = [];

// ════ SINGLE IMAGES ════
images.forEach(img => {
  const templateId = extractTemplateId(img['Preferred Template'])
    || tpl.single_image[img.Pillar]
    || tpl.single_image.Education;
  const templateName = extractTemplateName(img['Preferred Template']);
  const mediaUrls = parseMediaUrls(img['Media Urls']);
  requests.push({
    postId:       img.PostID,
    contentType:  'single_image',
    templateId,
    templateName,
    day:          img.Day,
    topic:        img.Topic       || '',
    hook:         img.Hook        || '',
    caption:      img.Caption     || '',
    hashtags:     img.Hashtags    || '',
    cta:          img.CTA         || '',
    visualBrief:  img.VisualBrief || '',
    layers: {
      headline: { text: (img.Hook || '').substring(0, 60) },
      subtext:  { text: (img.SlideText || '').substring(0, 30) }
    },
    mediaUrls,
    fileName:     img.PostID + '_single.jpg',
    format:       'jpg',
    folderName:   'SingleImage_Week_' + weekDate,
    pillar:       img.Pillar || ''
  });
});

// ════ CAROUSELS ════
carousels.forEach(car => {
  const templateId = extractTemplateId(car['Preferred Template'])
    || tpl.carousel[car.Pillar]
    || tpl.carousel.Education;
  const templateName = extractTemplateName(car['Preferred Template']);
  const mediaUrls = parseMediaUrls(car['Media Urls']);
  let slides = [];
  try {
    slides = JSON.parse(car.SlideDetails || '[]');
  } catch (e) {
    slides = [];
  }
  if (!Array.isArray(slides) || !slides.length) {
    slides = [{ slideNum: 1, title: car.Hook || 'Slide 1', description: '' }];
  }
  slides.forEach((sl, i) => {
    const slideMediaKey = `media_url_${i + 1}`;
    const slideMedia = mediaUrls.useDefaultMedia
      ? { useDefaultMedia: true }
      : mediaUrls[slideMediaKey]
        ? { useDefaultMedia: false, media_url_1: mediaUrls[slideMediaKey] }
        : { useDefaultMedia: true };
    requests.push({
      postId:       car.PostID,
      contentType:  'carousel',
      slideNum:     i + 1,
      totalSlides:  slides.length,
      templateId,
      templateName,
      day:          car.Day,
      topic:        car.Topic       || '',
      hook:         car.Hook        || '',
      caption:      car.Caption     || '',
      hashtags:     car.Hashtags    || '',
      cta:          car.CTA         || '',
      visualBrief:  car.VisualBrief || '',
      layers: {
        slide_title:  { text: (sl.title || 'Slide ' + (i + 1)).substring(0, 60) },
        slide_body:   { text: (sl.description || '').substring(0, 100) },
        slide_number: { text: (i + 1) + ' of ' + slides.length }
      },
      mediaUrls:    slideMedia,
      allMediaUrls: mediaUrls,
      fileName:     car.PostID + '_slide_' + String(i + 1).padStart(2, '0') + '.jpg',
      format:       'jpg',
      folderName:   'Carousels_Week_' + weekDate,
      pillar:       car.Pillar || ''
    });
  });
});

// ════ REELS ════
reels.forEach(rel => {
  const templateId = extractTemplateId(rel['Preferred Template'])
    || tpl.reel[rel.Pillar]
    || tpl.reel.Education;
  const templateName = extractTemplateName(rel['Preferred Template']);
  const mediaUrls = parseMediaUrls(rel['Media Urls']);
  const duration  = extractDuration(rel['Preferred Template']);
  const reelLayers = {
    scene1_text: { text: (rel.Hook || 'Hook').substring(0, 60) },
    scene2_text: { text: 'Setup' },
    scene3_text: { text: 'Value' },
    scene4_text: { text: (rel.CTA || 'Follow!').substring(0, 40) }
  };
  let scenes = [];
  try {
    scenes = JSON.parse(rel.SceneBreakdown || '[]');
  } catch (e) {}
  if (scenes.length >= 4) {
    reelLayers.scene2_text.text = (scenes[1].action || 'Setup').substring(0, 60);
    reelLayers.scene3_text.text = (scenes[2].action || 'Value').substring(0, 60);
  }
  requests.push({
    postId:       rel.PostID,
    contentType:  'reel',
    templateId,
    templateName,
    day:          rel.Day,
    topic:        rel.Topic       || '',
    hook:         rel.Hook        || '',
    caption:      rel.Caption     || '',
    hashtags:     rel.Hashtags    || '',
    cta:          rel.CTA         || '',
    visualBrief:  rel.VisualBrief || '',
    layers:       reelLayers,
    duration,
    mediaUrls,
    fileName:     rel.PostID + '_reel.mp4',
    format:       'mp4',
    folderName:   'Reels_Week_' + weekDate,
    pillar:       rel.Pillar || ''
  });
});

// ════ STORIES ════
stories.forEach(st => {
  const templateId = extractTemplateId(st['Preferred Template'])
    || tpl.story[st.StoryType]
    || tpl.story.Image;
  const templateName = extractTemplateName(st['Preferred Template']);
  const mediaUrls = parseMediaUrls(st['Media Urls']);
  requests.push({
    postId:       st.PostID,
    contentType:  'story',
    templateId,
    templateName,
    day:          st.Day,
    topic:        st.Topic       || '',
    hook:         st.Hook        || '',
    caption:      st.Caption     || '',
    hashtags:     st.Hashtags    || '',
    cta:          st.CTA         || '',
    visualBrief:  st.VisualBrief || '',
    pillar:       st.Pillar      || '',
    storyType:    st.StoryType          || 'Image',
    mainText:     st.MainText           || '',
    supportText:  st.SupportText        || '',
    background:   st.Background         || '',
    feedLink:     st.FeedPostConnection || '',
    layers: {
      main_text:    { text: (st.MainText    || 'Story').substring(0, 50) },
      support_text: { text: (st.SupportText || '').substring(0, 30) }
    },
    interactiveElement: (() => {
      try { return JSON.parse(st.InteractiveElement || '{}'); } catch(e) { return {}; }
    })(),
    mediaUrls,
    fileName:     st.PostID + '.jpg',
    format:       'jpg',
    folderName:   'Stories_Week_' + weekDate
  });
});

return requests.map(r => ({ json: r }));

const inp = $input.all();
const results = [];

for (const item of inp) {
  try {
    const json        = item.json;
    const fileName    = json.fileName || '';
    const isUrl       = fileName.startsWith('http://') || fileName.startsWith('https://');
    const contentType = (json.contentType || '').toLowerCase();

    const filteredData = {
      topic:       json.topic       || '',
      hook:        json.hook        || '',
      caption:     json.caption     || '',
      cta:         json.cta         || '',
      visualBrief: json.visualBrief || '',
      filename:    isUrl ? fileName : 'no file is provided'
    };

    if (contentType === 'reel') {
      filteredData.duration = json.duration || 'use_template_default';
    }

    results.push({
      json: {
        stringified: JSON.stringify(filteredData, null, 2)
      }
    });

  } catch (error) {
    console.error('Failed to process item:', error);
  }
}

return results;

// ============================================================
//  CODE IN JAVASCRIPT — v2
//  Outputs RAW JSON items (no stringification)
// ============================================================

const loopItem    = $('Process Items').item.json;
const contentType = (loopItem.contentType || '').toLowerCase();

const placidTemplateData = $input.all().map(i => i.json);

const results = [];

// ── CAROUSEL with templates array ──
if (
  contentType === 'carousel' &&
  Array.isArray(loopItem.templates) &&
  loopItem.templates.length > 0
) {
  for (const pageTemplate of loopItem.templates) {

    const { templates, ...itemWithoutTemplates } = loopItem;

    results.push({
      json: {
        // ── All original fields (no templates array) ──
        ...itemWithoutTemplates,

        // ── Updated per-page fields ──
        slideNum:     pageTemplate.pageNum,
        totalSlides:  loopItem.templates.length,
        templateId:   pageTemplate.uuid,
        templateName: pageTemplate.name,
        fileName:     loopItem.postId + '_slide_' + String(pageTemplate.pageNum).padStart(2, '0') + '.jpg',

        // ── Single page template object ──
        template: {
          pageNum: pageTemplate.pageNum,
          uuid:    pageTemplate.uuid,
          name:    pageTemplate.name,
          layers:  pageTemplate.layers || []
        },

        // ── Placid API response (raw) ──
        placidTemplateLayers: placidTemplateData
      }
    });
  }

} else {
  // ── Non-carousel: pass through as raw item ──
  results.push({
    json: {
      ...loopItem,
      placidTemplateLayers: placidTemplateData
    }
  });
}

return results;

// ============================================================
//  CLEAN GPT OUTPUT + FORMAT FOR PLACID API
//  - Images / Stories / Carousel pages → Placid /images body
//  - Reels → Placid /videos body (clips format)
//  - preview: true → FREE watermarked test (no credits used)
//  - Updated for Gemini response format
// ============================================================

const items       = $input.all();
const contentType = ($('Process Items').item.json.contentType || '').toLowerCase();
const templateId  = $('Process Items').item.json.templateId  || '';
const duration    = $('Process Items').item.json.duration    || null;

return items.map((item, index) => {
  try {

    // ✅ CHANGED — Gemini format: content.parts[0].text
    // Ignore thoughtSignature — only use text field
    const outputText = item.json.content.parts[0].text;

    // Strip markdown code fences
    let cleanJson = outputText
      .replace(/```json\s*/gi, '')
      .replace(/```javascript\s*/gi, '')
      .replace(/```\s*/g, '')
      .trim();

    // Extract first JSON object if there is extra text
    const jsonMatch = cleanJson.match(/\{[\s\S]*\}/);
    if (jsonMatch) cleanJson = jsonMatch[0];

    let parsed;
    try {
      parsed = JSON.parse(cleanJson);
    } catch (parseErr) {
      throw new Error('JSON parse failed: ' + parseErr.message);
    }

    // Ensure template_uuid is always set
    if (!parsed.template_uuid && templateId) {
      parsed.template_uuid = templateId;
    }

    let bodyObj;

    if (contentType === 'reel') {
      // ── Placid /videos API: clips array format ──
      const clip = {
        template_uuid: parsed.template_uuid || templateId,
        layers:        parsed.layers || {}
      };
      if (duration && duration !== 'use_template_default') {
        clip.duration = parseInt(duration, 10);
      }
      bodyObj = {
        preview: true,
        clips:   [clip]
      };

    } else {
      // ── Placid /images API: direct format ──
      bodyObj = {
        preview:       true,
        template_uuid: parsed.template_uuid || templateId,
        layers:        parsed.layers || {},
        create_now:    true
      };
    }

    return {
      json: {
        body:        JSON.stringify(bodyObj),
        contentType: contentType
      },
      pairedItem: { item: index }
    };

  } catch (error) {
    // ── Fallback bodies (also with preview: true) ──
    const fallback = contentType === 'reel'
      ? JSON.stringify({
          preview: true,
          clips:   [{ template_uuid: templateId, layers: {} }]
        })
      : JSON.stringify({
          preview:       true,
          template_uuid: templateId,
          layers:        {},
          create_now:    true
        });

    return {
      json: {
        body:        fallback,
        error:       'Gemini parse failed: ' + error.message,
        contentType: contentType
      },
      pairedItem: { item: index }
    };
  }
});

// ============================================================
//  TRACK RESULT — v2
//  Reads aggregated data array, groups by postId
// ============================================================

// ── Aggregate node wraps everything into a single data[] array ──
const aggregatedData = $input.first().json.data || [];

// ── Group all slides/items by postId ──
const groupedByPostId = {};

for (const item of aggregatedData) {
  const postId   = item.postId   || 'unknown';
  const slideNum = item.slideNum || 0;

  // ── Extract Drive URL ──
  let driveUrl = '';
  if (item.content && item.content.download_url) {
    driveUrl = item.content.download_url;
  } else {
    driveUrl = item.webViewLink || item.webContentLink || '';
  }

  // ── Extract Drive File ID ──
  let driveFileId = '';
  if (item.content && item.content.path) {
    driveFileId = item.content.path;
  } else {
    driveFileId = item.id || '';
  }

  // ── Init group on first encounter ──
  if (!groupedByPostId[postId]) {
    groupedByPostId[postId] = {
      // Post identification
      contentType:  item.contentType  || '',
      totalSlides:  item.totalSlides  || 1,

      // Template info
      templateId:   item.templateId   || '',
      templateName: item.templateName || '',

      // Content metadata
      day:         item.day         || '',
      topic:       item.topic       || '',
      pillar:      item.pillar      || '',
      hook:        item.hook        || '',
      caption:     item.caption     || '',
      hashtags:    item.hashtags    || '',
      cta:         item.cta         || '',
      visualBrief: item.visualBrief || '',

      // File info
      folderName: item.folderName || '',
      format:     item.format     || '',

      slides: []
    };
  }

  // ── Push this slide into the group ──
  groupedByPostId[postId].slides.push({
    slideNum,
    fileName:    item.fileName  || '',
    renderUrl:   item.renderUrl || '',
    status:      item.status    || 'unknown',
    driveFileId,
    driveUrl
  });
}

// ── Build final output — one item per postId ──
const results = [];

for (const postId of Object.keys(groupedByPostId)) {
  const meta = groupedByPostId[postId];

  // Sort slides by slideNum
  const slides = meta.slides.sort((a, b) => a.slideNum - b.slideNum);

  results.push({
    json: {
      // Post identification
      postId,
      contentType: meta.contentType,
      totalSlides: meta.totalSlides,

      // Template info
      templateId:   meta.templateId,
      templateName: meta.templateName,

      // Content metadata
      day:         meta.day,
      topic:       meta.topic,
      pillar:      meta.pillar,
      hook:        meta.hook,
      caption:     meta.caption,
      hashtags:    meta.hashtags,
      cta:         meta.cta,
      visualBrief: meta.visualBrief,

      // File info
      folderName: meta.folderName,
      format:     meta.format,

      // All slides grouped with their own renderUrl
      slides,

      // Flat arrays for quick access
      allRenderUrls:   slides.map(s => s.renderUrl).filter(Boolean).join(', '),
      allDriveUrls:    slides.map(s => s.driveUrl).filter(Boolean).join(', '),
      allDriveFileIds: slides.map(s => s.driveFileId).filter(Boolean).join(', '),

      success: true
    }
  });
}

console.log(`✅ Grouped ${aggregatedData.length} items into ${results.length} post(s)`);
return results;

const results = $('Track Result').all().map(i => i.json);
const total   = results.length;
const done    = results.filter(r => r.success).length;

const imgs    = results.filter(r => r.contentType === 'single_image');
const cars    = results.filter(r => r.contentType === 'carousel');
const reels   = results.filter(r => r.contentType === 'reel');
const stories = results.filter(r => r.contentType === 'story');
const rate    = total > 0 ? Math.round(done / total * 100) : 0;

// ── Build byPost from actual fields in Track Result output ──
const byPost = {};
results.forEach(r => {
  if (!byPost[r.postId]) {
    byPost[r.postId] = {
      contentType: r.contentType,
      totalSlides: r.totalSlides || 1,
      renderUrls:  [],
      urls:        [],
      slides:      []
    };
  }

  // ── allRenderUrls is a comma-separated string → split into array ──
  if (r.allRenderUrls) {
    r.allRenderUrls.split(', ').forEach(url => {
      if (url) byPost[r.postId].renderUrls.push(url);
    });
  }

  // ── allDriveUrls is a comma-separated string → split into array ──
  if (r.allDriveUrls) {
    r.allDriveUrls.split(', ').forEach(url => {
      if (url) byPost[r.postId].urls.push(url);
    });
  }

  // ── slides[] exists directly on each result ──
  if (Array.isArray(r.slides)) {
    r.slides.forEach(s => {
      byPost[r.postId].slides.push({
        num:       s.slideNum,
        renderUrl: s.renderUrl || '',
        url:       s.driveUrl  || '',
        fileName:  s.fileName  || ''
      });
    });
  }
});

return [{
  json: {
    results,
    byPost,
    stats: {
      total,
      done,
      failed:         total - done,
      rate,
      images:         imgs.length,
      carouselSlides: cars.length,
      reels:          reels.length,
      stories:        stories.length
    }
  }
}];

const data    = $('Collect Results').first().json;
const results = data.results || [];
const cal     = $('Read Calendar').all().map(i => i.json);

// ── Start with a copy of all calendar rows unchanged ──
const calMap = {};
cal.forEach(row => {
  calMap[row.PostID] = { ...row };
});

// ── Loop results and stamp URLs only into the EXACT matching postId ──
for (const r of results) {
  const postId      = r.postId;
  const contentType = (r.contentType || '').toLowerCase().trim();

  // ── Only update if postId exists in calendar ──
  if (!calMap[postId]) continue;

  let mainRender = '';
  let slideUrls  = '';

  if (contentType === 'carousel') {
    const sorted = (r.slides || [])
      .sort((a, b) => a.slideNum - b.slideNum)
      .map(s => s.renderUrl)
      .filter(Boolean);
    mainRender = sorted.join(', ');
    slideUrls  = mainRender;

  } else if (contentType === 'reel') {
    mainRender = r.allRenderUrls || '';

  } else if (contentType === 'single_image') {
    mainRender = (r.allRenderUrls || '').split(', ')[0] || '';

  } else if (contentType === 'story') {
    mainRender = (r.allRenderUrls || '').split(', ')[0] || '';
  }

  // ── Only stamp if we have a real URL ──
  if (mainRender) {
    calMap[postId].Visual_URL     = mainRender;
    calMap[postId].Render_URL     = mainRender;
    calMap[postId].Slide_URLs     = slideUrls;
    calMap[postId].Visual_Created = true;
    calMap[postId].Status         = 'visuals_created';
  }
}

// ── Return all calendar rows — updated ones have URLs, rest unchanged ──
return Object.values(calMap).map(row => ({ json: row }));

// ============================================================
//  EXTRACT TEMPLATE CONFIGURATION — Universal v3
//  Works for: carousel, reel, single_image, story
//  Input: Loop Over Items
//  Output: Stringified template config for AI prompt
// ============================================================

const item = $input.first().json;

// ── Extract core info ──
const contentType  = item.contentType || '';
const slideNum     = item.slideNum    || 1;
const sceneNum     = item.sceneNum    || 1;
const totalSlides  = item.totalSlides || item.totalScenes || 1;
const templateId   = item.templateId  || '';
const templateName = item.templateName || '';

// ── UNIVERSAL: Extract layers from wherever they exist ──
let templateLayers = [];

// Priority 1: Check currentTemplate (new per-slide structure)
if (item.currentTemplate && item.currentTemplate.layers) {
  templateLayers = item.currentTemplate.layers;
  console.log(`Using currentTemplate.layers (${templateLayers.length} layers)`);
}
// Priority 2: Check templates array (multi-template fallback)
else if (item.templates && Array.isArray(item.templates) && item.templates.length > 0) {
  const currentIndex = (slideNum || sceneNum || 1) - 1;
  const currentTemplate = item.templates[currentIndex] || item.templates[0];
  templateLayers = currentTemplate.layers || [];
  console.log(`Using templates[${currentIndex}].layers (${templateLayers.length} layers)`);
}
// Priority 3: Check single template object (legacy carousel structure)
else if (item.template && item.template.layers) {
  templateLayers = item.template.layers;
  console.log(`Using template.layers (${templateLayers.length} layers)`);
}
// Priority 4: Check matchedTemplate (from single_image, story)
else if (item.matchedTemplate && item.matchedTemplate.layers) {
  templateLayers = item.matchedTemplate.layers;
  console.log(`Using matchedTemplate.layers (${templateLayers.length} layers)`);
}
// Priority 5: No template found
else {
  console.log('⚠️ No template layers found in item');
}

// ── Filter layers by type ──
const textLayers    = templateLayers.filter(l => l.type === 'text');
const pictureLayers = templateLayers.filter(l => l.type === 'picture');

// ── Determine context based on content type ──
const contextInfo = contentType === 'carousel'
  ? { currentPage: slideNum, totalPages: totalSlides, pageType: 'slide' }
  : contentType === 'reel'
  ? { currentScene: sceneNum, totalScenes: totalSlides, pageType: 'scene' }
  : contentType === 'story'
  ? { storyType: item.storyType || 'Image', pageType: 'story' }
  : { pageType: 'single' };

// ── Extract content to fill (universal for all types) ──
const content = {
  topic:       item.topic       || '',
  hook:        item.hook        || '',
  caption:     item.caption     || '',
  cta:         item.cta         || '',
  visualBrief: item.visualBrief || ''
};

// Add content type-specific fields
if (contentType === 'reel') {
  content.duration = item.duration || 'use_template_default';
}

if (contentType === 'story') {
  content.storyType          = item.storyType          || 'Image';
  content.mainText           = item.mainText           || '';
  content.supportText        = item.supportText        || '';
  content.background         = item.background         || '';
  content.interactiveElement = item.interactiveElement || {};
}

// Handle media URLs
if (item.mediaUrls) {
  if (item.mediaUrls.useDefaultMedia) {
    content.mediaUrl = 'no file is provided';
  } else {
    content.mediaUrl = item.mediaUrls.media_url_1 || 'no file is provided';
  }
} else {
  content.mediaUrl = 'no file is provided';
}

// ── Build clean template config object ──
const templateConfig = {
  // Context info (varies by content type)
  ...contextInfo,

  // Template identification
  templateId:   templateId,
  templateName: templateName,
  contentType:  contentType,

  // Layer summary
  totalLayers:        templateLayers.length,
  totalTextLayers:    textLayers.length,
  totalPictureLayers: pictureLayers.length,

  // Full layer list with types
  layers: templateLayers.map(l => ({
    name: l.name,
    type: l.type
  })),

  // Separated by type for easy AI reference
  textLayerNames:    textLayers.map(l => l.name),
  pictureLayerNames: pictureLayers.map(l => l.name),

  // Content to fill into layers
  content: content
};

console.log('Template config built:');
console.log(`  Content Type: ${contentType}`);
console.log(`  Template: ${templateName} (${templateId})`);
console.log(`  Total Layers: ${templateLayers.length} (${textLayers.length} text, ${pictureLayers.length} picture)`);

return [
  {
    json: {
      stringified: JSON.stringify(templateConfig, null, 2)
    }
  }
];

