// ============================================================
//  EXTRACT RENDER URLS + METADATA
//  Pulls rendered URLs from Placid + metadata from Process Items loop
// ============================================================

const allInputs = $input.all();

// ── Pull metadata from the Process Items loop node ──
const loopData = $('Process Items').item.json;

const pageUrls = [];

for (const inp of allInputs) {
  const data = inp.json;
  let renderUrl = '';

  // ── Placid image response ──
  if (data.image_url) {
    renderUrl = data.image_url;
  }
  // ── Placid video response (after polling) ──
  else if (data.video_url) {
    renderUrl = data.video_url;
  }
  // ── Placid video queued (polling_url available) ──
  else if (data.status === 'queued' && data.polling_url) {
    renderUrl = data.polling_url;
  }
  // ── Legacy / fallback ──
  else if (data.render_url) {
    renderUrl = data.render_url;
  } else if (data.url) {
    renderUrl = data.url;
  } else if (data.result && data.result.url) {
    renderUrl = data.result.url;
  }

  if (renderUrl) {
    pageUrls.push({
      // ── Render info ──
      page:      data.page || ('page-' + (pageUrls.length + 1)),
      renderUrl: renderUrl,
      status:    data.status || 'unknown',

      // ── Post identification ──
      postId:      loopData.postId      || '',
      contentType: loopData.contentType || '',
      slideNum:    loopData.slideNum    || 1,
      totalSlides: loopData.totalSlides || 1,

      // ── Template info ──
      templateId:   loopData.templateId   || '',
      templateName: loopData.templateName || '',

      // ── Content metadata ──
      day:         loopData.day         || '',
      topic:       loopData.topic       || '',
      pillar:      loopData.pillar      || '',
      hook:        loopData.hook        || '',
      caption:     loopData.caption     || '',
      hashtags:    loopData.hashtags    || '',
      cta:         loopData.cta         || '',
      visualBrief: loopData.visualBrief || '',

      // ── File info ──
      fileName:   loopData.fileName   || '',
      format:     loopData.format     || '',
      folderName: loopData.folderName || '',

      // ── Layer mapping used ──
      layers: loopData.layers || {}
    });
  }
}

return pageUrls.map((item, index) => ({
  json: item,
  pairedItem: { item: index }
}));

