// ============================================================
//  FORMAT TELEGRAM APPROVAL MESSAGE
//  Sends all content with rendered visual URLs + 4 action buttons
// ============================================================

const cfg = $('Get row(s) in sheet1').first().json;
const collectData = $('Collect Results').first().json;
const results = collectData.results || [];
const stats = collectData.stats || {};

const telegramToken = cfg.telegramBotToken || '';
const chatId = cfg.telegramChatId || '';

if (!telegramToken || !chatId || telegramToken === 'YOUR_BOT_TOKEN') {
  return [{ json: { skip: true, reason: 'Telegram not configured' } }];
}

// Build batch ID for this week
const now = new Date();
const batchId = 'BATCH_' + now.toISOString().split('T')[0];

// Separate feed posts and stories
const feedPosts = results.filter(r => 
  r.contentType === 'single_image' || r.contentType === 'carousel' || r.contentType === 'reel'
);
const stories = results.filter(r => r.contentType === 'story');

// Build feed posts message
let feedMsg = `🎨 *VISUALS READY FOR REVIEW*\n`;
feedMsg += `Week Batch: \`${batchId}\`\n\n`;
feedMsg += `━━━ FEED POSTS (${feedPosts.length}) ━━━\n\n`;

let postIndex = 1;
for (const r of feedPosts) {
  const typeEmoji = r.contentType === 'carousel' ? '🎠' : 
                    r.contentType === 'reel' ? '🎬' : '📸';
  const typeLabel = r.contentType.toUpperCase().replace('_', ' ');

  feedMsg += `${postIndex}️⃣ ${r.day || ''} — ${typeLabel} ${typeEmoji}\n`;
  feedMsg += `📌 ID: \`${r.postId}\`\n`;
  feedMsg += `📝 Topic: ${r.topic || 'N/A'}\n`;
  feedMsg += `🎣 Hook: ${(r.hook || '').substring(0, 50)}${(r.hook || '').length > 50 ? '...' : ''}\n`;
  feedMsg += `📊 Caption: ${(r.caption || '').split(/\s+/).length} words\n`;

  if (r.contentType === 'carousel' && r.allRenderUrls) {
    const slides = r.allRenderUrls.split(', ');
    feedMsg += `🖼️ ${slides.length} slides rendered\n`;
  } else if (r.allRenderUrls) {
    feedMsg += `🖼️ Visual: Ready ✅\n`;
  }

  feedMsg += `🏷️ Pillar: ${r.pillar || 'N/A'}\n\n`;
  postIndex++;
}

// Story summary (compact)
if (stories.length > 0) {
  feedMsg += `━━━ STORIES (${stories.length}) ━━━\n`;
  feedMsg += `📱 ${stories.length} stories rendered and ready\n\n`;
}

// Stats
feedMsg += `━━━ SUMMARY ━━━\n`;
feedMsg += `✅ Total: ${stats.done || 0}/${stats.total || 0} files (${stats.rate || 0}%)\n`;
feedMsg += `📸 Images: ${stats.images || 0} | 🎠 Carousels: ${stats.carouselSlides || 0} slides\n`;
feedMsg += `🎬 Reels: ${stats.reels || 0} | 📱 Stories: ${stats.stories || 0}\n\n`;
feedMsg += `💬 To make changes, click a button below.\n`;
feedMsg += `Reference the *Post ID* when sending changes.`;

// Build inline keyboard with 4 buttons
const keyboard = {
  inline_keyboard: [
    [
      { text: '✅ Approve & Schedule', callback_data: `approve_all|${batchId}` },
      { text: '🖼️ Change Image', callback_data: `change_image|${batchId}` }
    ],
    [
      { text: '✏️ Change Text', callback_data: `change_text|${batchId}` },
      { text: '🔄 Regenerate', callback_data: `regenerate|${batchId}` }
    ]
  ]
};

// Split message if too long (Telegram 4096 char limit)
const messages = [];
if (feedMsg.length > 4000) {
  // Split into feed posts and stats
  const splitPoint = feedMsg.lastIndexOf('━━━ STORIES', 3900);
  if (splitPoint > 0) {
    messages.push({ text: feedMsg.substring(0, splitPoint).trim(), keyboard: null });
    messages.push({ text: feedMsg.substring(splitPoint).trim(), keyboard: keyboard });
  } else {
    messages.push({ text: feedMsg.substring(0, 4000) + '...', keyboard: null });
    messages.push({ text: '...' + feedMsg.substring(4000), keyboard: keyboard });
  }
} else {
  messages.push({ text: feedMsg, keyboard: keyboard });
}

return [{
  json: {
    telegramToken,
    chatId,
    messages,
    batchId,
    skip: false
  }
}];

// Send Telegram message(s) with inline keyboard buttons
const data = $input.first().json;

if (data.skip) {
  return [{ json: { sent: false, reason: data.reason } }];
}

const token = data.telegramToken;
const chatId = data.chatId;
const messages = data.messages || [];

const results = [];

for (let i = 0; i < messages.length; i++) {
  const msg = messages[i];

  const body = {
    chat_id: chatId,
    text: msg.text,
    parse_mode: 'Markdown'
  };

  // Add inline keyboard to the last message
  if (msg.keyboard) {
    body.reply_markup = msg.keyboard;
  }

  try {
    const response = await $helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${token}/sendMessage`,
      body: body,
      headers: { 'Content-Type': 'application/json' },
      returnFullResponse: true
    });

    results.push({
      messageIndex: i,
      sent: true,
      messageId: response.body?.result?.message_id || null
    });

    // Small delay between messages
    if (i < messages.length - 1) {
      await new Promise(resolve => setTimeout(resolve, 500));
    }
  } catch (error) {
    results.push({
      messageIndex: i,
      sent: false,
      error: error.message
    });
  }
}

return [{ json: { sent: true, results, batchId: data.batchId } }];
